  ('bookkeeper-moex-01288', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行遺產及贈與稅法之規定，下列敘述何者正確？ 應課贈與稅之贈與行為應於行為發生後2個月內辦理申報 應課贈與稅之贈與人死亡時，贈與稅尚未核課，改由遺囑執行人為納稅義務人 遺產稅的課稅級距金額，適用物價指數調整，並以萬元為調整單位 被繼承人遺有父母者，每人得自遺產總額扣除120萬元', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 49, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
